select 
from comment
where status = 0
and entity_type = #{entityType}
and entity_id = #{entityId}
order by create_time asc
limit #{offset}, #{limit}

select count(id)
from comment
where status = 0
  and entity_type = #{entityType}
  and entity_id = #{entityId}

select u.cid as id, u.user_id as user_id, 1 as entity_type, u.post_id as entity_id, 0 as target_id, '' as content, 0 as status, u.create_time as create_time, null as update_time, 0 as edit_count, 0 as deleted_by, '' as deleted_reason, null as deleted_time from ( select c.entity_id as post_id, c.user_id as user_id, c.create_time as create_time, c.id as cid from comment c where c.status = 0 and c.entity_type = 1 and c.entity_id in
#{pid}
union all
select p.entity_id as post_id, r.user_id as user_id, r.create_time as create_time, r.id as cid from comment r join comment p on r.entity_type = 2 and r.entity_id = p.id where r.status = 0 and p.status = 0 and p.entity_type = 1 and p.entity_id in
#{pid}
) u inner join ( select post_id, max(create_time) as max_time from ( select c.entity_id as post_id, c.create_time as create_time from comment c where c.status = 0 and c.entity_type = 1 and c.entity_id in
#{pid}
union all
select p.entity_id as post_id, r.create_time as create_time from comment r join comment p on r.entity_type = 2 and r.entity_id = p.id where r.status = 0 and p.status = 0 and p.entity_type = 1 and p.entity_id in
#{pid}
) t group by post_id ) m on u.post_id = m.post_id and u.create_time = m.max_time order by u.post_id asc, u.cid desc

mapper.update:
update comment
set status = #{status},
    deleted_by = #{deletedBy},
    deleted_reason = #{deletedReason},
    deleted_time = #{deletedTime}
where id = #{id}
